import sys
from typing import List

class Solution:
    def solve(self, graph: List[List[int]]) -> bool:
        visited = [0] * len(graph)
        for i in range(len(graph)):
            if visited[i] == 0:
                if self.dfs(graph, visited, i):
                    return True
        return False

    def dfs(self, graph, visited, node):
        if visited[node] == 1:
            return True
        if visited[node] == 2:
            return False
        visited[node] = 1
        for neighbor in graph[node]:
            if self.dfs(graph, visited, neighbor):
                return True
        visited[node] = 2
        return False

if __name__ == '__main__':
