#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool solve(vector<vector<int>>& graph) {
        vector<int> visited(graph.size(), 0);
        for (int i = 0; i < graph.size(); i++) {
            if (visited[i] == 0) {
                if (dfs(graph, visited, i)) {
                    return true;
                }
            }
        }
        return false;
    }
private:
    bool dfs(vector<vector<int>>& graph, vector<int>& visited, int node) {
        if (visited[node] == 1) {
            return true;
        }
        if (visited[node] == 2) {
            return false;
        }
        visited[node] = 1;
        for (int neighbor : graph[node]) {
            if (dfs(graph, visited, neighbor)) {
                return true;
            }
        }
        visited[node] = 2;
        return false;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V;
    cin >> V;
    vector<vector<int>> graph(V);
    for (int i = 0; i < V; i++) {
        int K;
        cin >> K;
        for (int j = 0; j < K; j++) {
            int neighbor;
            cin >> neighbor;
            graph[i].push_back(neighbor);
        }
    }
    Solution sol;
    cout << (sol.solve(graph) ? "true" : "false") << "\n";
    return 0;
}
